def run_command(cmd, cwd=None, env=None, timeout=600):
    """Run a subprocess command securely with timeout and validation."""
    # Security: only allow list-based commands, never shell=True
    if not isinstance(cmd, list):
        raise ValueError("Commands must be provided as a list, not a string")

    # Security: validate no shell metacharacters in arguments
    shell_metacharacters = set(";|&$`\\!#~")
    for arg in cmd:
        if any(c in arg for c in shell_metacharacters):
            raise ValueError(f"Shell metacharacters detected in command argument: {arg!r}")

    logger.info("Running: %s", " ".join(cmd))

    # Security: use restricted environment, don't inherit everything blindly
    safe_env = _build_safe_env(env)

    try:
        result = subprocess.run(
            cmd,
            cwd=cwd,
            env=safe_env,
            capture_output=True,
            text=True,
            timeout=timeout,
            shell=False,  # Security: never use shell=True
        )

        if result.stdout:
            logger.info(result.stdout)
        if result.stderr:
            # Security: filter potential secrets from stderr before logging
            filtered_stderr = _filter_sensitive_output(result.stderr)
            logger.warning(filtered_stderr)

        if result.returncode != 0:
            raise subprocess.CalledProcessError(
                result.returncode, cmd, result.stdout, result.stderr
            )

        return result
    except subprocess.TimeoutExpired:
        logger.error("Command timed out after %d seconds: %s", timeout, " ".join(cmd))
        raise


def _build_safe_env(extra_env=None):
    """Build a safe environment with only necessary variables."""
    # Security: allowlist of environment variables to pass through
    allowed_env_vars = {
        "PATH",
        "HOME",
        "USER",
        "LANG",
        "LC_ALL",
        "VIRTUAL_ENV",
        "PYTHONPATH",
        "PYTHONDONTWRITEBYTECODE",
        "PIP_NO_CACHE_DIR",
        "PIP_DISABLE_PIP_VERSION_CHECK",
        "CI",
        "GITHUB_ACTIONS",
        "GITLAB_CI",
        "JENKINS_URL",
        "TZ",
        "TMPDIR",
        "TERM",
    }

    safe_env = {}
    for key in allowed_env_vars:
        if key in os.environ:
            safe_env[key] = os.environ[key]

    # Security: force pip to use HTTPS only
    safe_env["PIP_REQUIRE_HASHES"] = "false"  # Set to true if using hash-pinned requirements
    safe_env["PYTHONDONTWRITEBYTECODE"] = "1"

    if extra_env:
        # Only allow known keys from extra_env
        for key, value in extra_env.items():
            if key in allowed_env_vars:
                safe_env[key] = value

    return safe_env


def _filter_sensitive_output(text):
    """Filter potential secrets and tokens from log output."""
    import re

    # Security: redact common secret patterns
    patterns = [
        (r'(?i)(password|passwd|pwd)\s*[=:]\s*\S+', r'\1=***REDACTED***'),
        (r'(?i)(token|api_key|apikey|secret|auth)\s*[=:]\s*\S+', r'\1=***REDACTED***'),
        (r'(?i)(authorization:\s*bearer\s+)\S+', r'\1***REDACTED***'),
        (r'(?i)(https?://)[^@\s]+@', r'\1***REDACTED***@'),
    ]

    filtered = text
    for pattern, replacement in patterns:
        filtered = re.sub(pattern, replacement, filtered)

    return filtered


def validate_requirements_file(filepath):
    """Validate the requirements.txt file for security issues."""
    filepath = Path(filepath).resolve()

    # Security: ensure the file is within the project directory
    project_root = Path.cwd().resolve()
    if not str(filepath).startswith(str(project_root)):
        raise ValueError(f"Requirements file must be within project directory: {filepath}")

    if not filepath.exists():
        raise FileNotFoundError(f"Requirements file not found: {filepath}")

    if not filepath.is_file():
        raise ValueError(f"Requirements path is not a file: {filepath}")

    # Security: check file size (prevent DoS with huge files)
    max_size = 1024 * 1024  # 1MB
    file_size = filepath.stat().st_size
    if file_size > max_size:
        raise ValueError(f"Requirements file too large: {file_size} bytes (max {max_size})")

    # Security: validate contents for suspicious entries
    suspicious_patterns = [
        "git+http://",  # Insecure git URLs (only allow https)
        "svn+http://",
        "--index-url http://",  # Insecure index URLs
        "--extra-index-url http://",
        "--trusted-host",  # Bypasses TLS verification
        "--find-links http://",
    ]

    lines = filepath.read_text(encoding="utf-8").splitlines()
    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        if not stripped or stripped.startswith("#"):
            continue

        for pattern in suspicious_patterns:
            if pattern in stripped.lower():
                raise ValueError(
                    f"Security issue in {filepath} line {line_num}: "
                    f"suspicious pattern '{pattern}' found in: {stripped}"
                )

    logger.info("Requirements file validated: %s (%d lines)", filepath, len(lines))
    return filepath


def compute_file_hash(filepath):
    """Compute SHA-256 hash of a file for integrity verification."""
    sha256 = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest()


def check_pip_version():
    """Ensure pip is at a secure minimum version."""
    result = run_command([sys.executable, "-m", "pip", "--version"])
    version_str = result.stdout.split()[1]
    major, minor = map(int, version_str.split(".")[:2])
    min_major, min_minor = map(int, MIN_PIP_VERSION.split(".")[:2])

    if (major, minor) < (min_major, min_minor):
        logger.warning(
            "pip version %s is below minimum %s, upgrading...",
            version_str,
            MIN_PIP_VERSION,
        )
        run_command([
            sys.executable, "-m", "pip", "install",
            "--upgrade", f"pip>={MIN_PIP_VERSION}"
        ])
    else:
        logger.info("pip version %s meets minimum requirement %s", version_str, MIN_PIP_VERSION)


