def _create_deployment_archive(dist_path):
    """Create a deployment archive excluding sensitive and unnecessary files."""
    import tarfile

    # Security: explicit allowlist of file patterns to include
    # and denylist of patterns to exclude
    exclude_patterns = {
        ".git",
        ".gitignore",
        ".env",
        ".env.local",
        ".env.production",
        "__pycache__",
        "*.pyc",
        "*.pyo",
        ".pytest_cache",
        ".mypy_cache",
        ".tox",
        "node_modules",
        ".venv",
        "venv",
        "env",
        ".idea",
        ".vscode",
        "*.egg-info",
        "dist",
        "build",
        ".secrets",
        "*.key",
        "*.pem",
        "*.p12",
        ".aws",
        ".docker",
        "docker-compose.override.yml",
        "Dockerfile.dev",
    }

    # Security: also exclude files that commonly contain secrets
    secret_file_patterns = {
        ".env",
        "credentials",
        "secrets",
        "*.key",
        "*.pem",
        "*.p12",
        "*.pfx",
        "*.jks",
        "id_rsa",
        "id_ed25519",
    }

    project_name = Path.cwd().name
    archive_name = f"{project_name}-deploy.tar.gz"
    archive_path = dist_path / archive_name

    def should_exclude(tarinfo):
        """Filter function for tar archive."""
        name = Path(tarinfo.name).name
        parts = set(Path(tarinfo.name).parts)

        # Check against exclude patterns
        for pattern in exclude_patterns:
            if pattern.startswith("*"):
                if name.endswith(pattern[1:]):
                    return None
            elif pattern in parts or name == pattern:
                return None

        # Security: double-check for secret files
        name_lower = name.lower()
        for pattern in secret_file_patterns:
            if pattern.startswith("*"):
                if name_lower.endswith(pattern[1:]):
                    logger.warning("Excluding potential secret file: %s", tarinfo.name)
                    return None
            elif pattern in name_lower:
                logger.warning("Excluding potential secret file: %s", tarinfo.name)
                return None

        # Security: don't include files with overly permissive permissions
        # Reset permissions to safe defaults
        tarinfo.uid = 0
        tarinfo.gid = 0
        tarinfo.uname = "root"
        tarinfo.gname = "root"
        if tarinfo.isdir():
            tarinfo.mode = 0o755
        else:
            tarinfo.mode = 0o644

        return tarinfo

    with tarfile.open(archive_path, "w:gz") as tar:
        tar.add(".", arcname=project_name, filter=should_exclude)

    logger.info("Deployment archive created: %s", archive_path)


